const posts = $input.all().map(i => i.json);

// Check each post for AI optimization signals
// Posts are scored on how likely they are to be cited by AI systems
const scoredPosts = posts.map(post => {
  const content = (post.content?.rendered || '').replace(/<[^>]+>/g, ' ');
  const title = post.title?.rendered || '';

  let score = 0;
  const issues = [];
  const strengths = [];

  // ── POSITIVE SIGNALS ──────────────────────────────────
  // 1. Has a clear definition in first paragraph
  const firstPara = content.split('\n').slice(0, 3).join(' ');
  if (firstPara.match(/is a |is the |refers to |defined as |means /i)) {
    score += 20; strengths.push('Has definition');
  } else {
    issues.push('Missing clear definition in opening paragraph');
  }

  // 2. Has numbered lists or step-by-step structure
  if (post.content?.rendered?.includes('<ol>') || post.content?.rendered?.includes('<li>')) {
    score += 15; strengths.push('Has structured lists');
  } else {
    issues.push('No structured lists — AI prefers enumerable content');
  }

  // 3. Has FAQ section
  if (content.toLowerCase().includes('frequently asked') || 
      post.content?.rendered?.includes('application/ld+json') && post.content?.rendered?.includes('FAQPage')) {
    score += 25; strengths.push('Has FAQ / FAQPage schema');
  } else {
    issues.push('Missing FAQ section — FAQs are highest-cited content type');
  }

  // 4. Has concise, quotable sentences (under 25 words)
  const sentences = content.match(/[^.!?]+[.!?]+/g) || [];
  const shortSentences = sentences.filter(s => s.trim().split(' ').length < 25).length;
  const shortRatio = shortSentences / Math.max(sentences.length, 1);
  if (shortRatio > 0.6) {
    score += 15; strengths.push('Good sentence length for citations');
  } else {
    issues.push('Sentences too long — AI prefers concise, quotable sentences');
  }

  // 5. Has specific numbers/statistics
  if (content.match(/\d+%|\d+ (times|hours|minutes|days|percent|steps|ways|tips)/i)) {
    score += 10; strengths.push('Has specific numbers');
  } else {
    issues.push('No specific numbers — add stats or quantified claims');
  }

  // 6. Has schema markup already
  if (post.content?.rendered?.includes('application/ld+json')) {
    score += 15; strengths.push('Has structured data schema');
  } else {
    issues.push('Missing JSON-LD schema — run WF12A first');
  }

  // ── NEGATIVE SIGNALS ──────────────────────────────────
  // Passive voice (AI cites authoritative, active statements)
  const passiveCount = (content.match(/\b(is|are|was|were|be|been|being)\s+\w+ed\b/gi) || []).length;
  if (passiveCount > 5) {
    score -= 10; issues.push(`High passive voice (${passiveCount} instances)`);
  }

  return {
    post_id: post.id,
    post_title: title,
    post_url: post.link,
    post_content: post.content?.rendered || '',
    ai_citation_score: score,
    grade: score >= 70 ? 'A' : score >= 50 ? 'B' : score >= 30 ? 'C' : 'D',
    strengths,
    issues,
    needs_optimization: score < 60
  };
});

// Return only posts that need optimization, sorted by lowest score first
const toOptimize = scoredPosts
  .filter(p => p.needs_optimization)
  .sort((a, b) => a.ai_citation_score - b.ai_citation_score)
  .slice(0, 5); // Process max 5 per run

return toOptimize.map(p => ({ json: p }));

const raw = $input.first().json;
const post = $('⚙️ Score Posts for AI Citation Potential').first().json;

let optimizations;
try {
  const content = raw?.message?.content || raw?.response || '';
  const match = content.match(/```json\n?([\s\S]*?)\n?```/) || content.match(/({[\s\S]*})/);
  optimizations = JSON.parse((match ? match[1] || match[0] : content).trim());
} catch(e) {
  optimizations = { error: true };
}

if (optimizations.error) {
  return [{ json: { skipped: true, post_id: post.post_id, reason: 'Parse error' } }];
}

let updatedContent = post.post_content;

// 1. Inject Quick Answer box after H1
if (optimizations.quick_answer_html) {
  updatedContent = updatedContent.replace(
    /(<\/h1>|<h1[^>]*>[^<]*<\/h1>)/i,
    `$1\n${optimizations.quick_answer_html}`
  );
}

// 2. Inject Key Takeaways after quick answer (or after H1)
if (optimizations.key_takeaways_html) {
  if (updatedContent.includes('quick-answer')) {
    updatedContent = updatedContent.replace(
      /(class=["']quick-answer["'][^>]*>.*?<\/div>)/is,
      `$1\n${optimizations.key_takeaways_html}`
    );
  }
}

// 3. Replace or append FAQ section
if (optimizations.new_faq_section_html) {
  if (updatedContent.toLowerCase().includes('frequently asked')) {
    // Replace existing FAQ
    updatedContent = updatedContent.replace(
      /<h2[^>]*>[^<]*[Ff]requently[^<]*<\/h2>[\s\S]*?(?=<h2|$)/i,
      optimizations.new_faq_section_html + '\n'
    );
  } else {
    // Append before last CTA paragraph
    updatedContent += '\n' + optimizations.new_faq_section_html;
  }
}

// 4. Update FAQPage schema with new entries
if (optimizations.faq_schema_entries?.length) {
  const newFaqSchema = {
    '@context': 'https://schema.org',
    '@type': 'FAQPage',
    'mainEntity': optimizations.faq_schema_entries.map(q => ({
      '@type': 'Question',
      'name': q.question,
      'acceptedAnswer': { '@type': 'Answer', 'text': q.answer }
    }))
  };

  const newSchemaTag = `<script type="application/ld+json">${JSON.stringify(newFaqSchema)}</script>`;

  // Replace existing FAQ schema or prepend
  if (updatedContent.includes('FAQPage')) {
    updatedContent = updatedContent.replace(
      /<script type="application\/ld\+json">[\s\S]*?FAQPage[\s\S]*?<\/script>/i,
      newSchemaTag
    );
  } else {
    updatedContent = newSchemaTag + '\n' + updatedContent;
  }
}

return [{ json: {
  post_id: post.post_id,
  post_title: post.post_title,
  original_score: post.ai_citation_score,
  estimated_new_score: optimizations.estimated_new_score || post.ai_citation_score + 25,
  optimization_summary: optimizations.optimization_summary,
  updated_content: updatedContent,
  changes_made: [
    optimizations.quick_answer_html ? 'Added Quick Answer box' : null,
    optimizations.key_takeaways_html ? 'Added Key Takeaways' : null,
    optimizations.new_faq_section_html ? 'Expanded FAQ section' : null,
    optimizations.faq_schema_entries?.length ? 'Updated FAQPage schema' : null
  ].filter(Boolean)
}}];
